"use client";

import { useMemo, useState } from "react";
import { AppShell } from "@/components/layout/AppShell";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import { cn } from "@/lib/utils";
import { useTranslation } from "@/i18n";
import { useConfig } from "@/hooks/useConfig";
import { REGISTERED_MODELS, getModelsByCategory } from "@/services/modelSchema";
import {
  Cpu,
  ImageIcon,
  Video,
  Check,
  Sparkles,
  Zap,
  Settings,
  ChevronRight,
} from "lucide-react";
import Link from "next/link";

export default function ModelsPage() {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState("all");
  const { textToImageModel, imageToImageModel, textToVideoModel, imageToVideoModel,
    setTextToImageModel, setImageToImageModel, setTextToVideoModel, setImageToVideoModel } = useConfig();

  const imageModels = getModelsByCategory("image");
  const videoModels = getModelsByCategory("video");

  const filteredModels = useMemo(() => {
    switch (activeTab) {
      case "image": return imageModels;
      case "video": return videoModels;
      default: return REGISTERED_MODELS;
    }
  }, [activeTab, imageModels, videoModels]);

  return (
    <AppShell>
      <div className="mx-auto max-w-6xl space-y-6">
        {/* Header */}
        <div className="flex items-center gap-3">
          <div className="inline-flex rounded-xl bg-gradient-to-br from-cyan-500 to-blue-500 p-2.5 text-white shadow-lg shadow-blue-500/20">
            <Cpu className="h-6 w-6" />
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">{t("models.title")}</h1>
            <p className="text-sm text-muted-foreground">
              浏览可用模型并设置默认生成模型
            </p>
          </div>
          <div className="ml-auto">
            <Button variant="outline" size="sm" asChild>
              <Link href="/settings">
                <Settings className="mr-1.5 h-4 w-4" />
                API 配置
              </Link>
            </Button>
          </div>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList>
            <TabsTrigger value="all">全部 ({REGISTERED_MODELS.length})</TabsTrigger>
            <TabsTrigger value="image">图片模型 ({imageModels.length})</TabsTrigger>
            <TabsTrigger value="video">视频模型 ({videoModels.length})</TabsTrigger>
          </TabsList>

          <TabsContent value={activeTab} className="mt-6">
            <div className="grid gap-4 sm:grid-cols-2">
              {filteredModels.map((model) => {
                const isImageDefault = model.id === textToImageModel || model.id === imageToImageModel;
                const isVideoDefault = model.id === textToVideoModel || model.id === imageToVideoModel;
                const isDefault = isImageDefault || isVideoDefault;

                return (
                  <Card key={model.id} className={cn(
                    "transition-all hover:shadow-md",
                    isDefault && "border-primary/50 bg-primary/5"
                  )}>
                    <CardHeader>
                      <div className="flex items-start justify-between">
                        <div className="flex items-center gap-2">
                          <div className={cn(
                            "rounded-lg p-2",
                            model.category === "image" 
                              ? "bg-purple-100 dark:bg-purple-900/30"
                              : "bg-emerald-100 dark:bg-emerald-900/30"
                          )}>
                            {model.category === "image" 
                              ? <ImageIcon className="h-4 w-4 text-purple-600 dark:text-purple-400" />
                              : <Video className="h-4 w-4 text-emerald-600 dark:text-emerald-400" />
                            }
                          </div>
                          <div>
                            <CardTitle className="text-sm">{model.name}</CardTitle>
                            <CardDescription className="text-xs">{model.id}</CardDescription>
                          </div>
                        </div>
                        {isDefault && (
                          <Badge variant="default" className="text-[10px] h-5">
                            <Check className="h-3 w-3 mr-1" />默认
                          </Badge>
                        )}
                      </div>
                    </CardHeader>
                    <CardContent className="space-y-3">
                      <p className="text-xs text-muted-foreground">{model.description}</p>

                      {/* 参数列表 */}
                      <div className="flex flex-wrap gap-1">
                        {model.params.slice(0, 5).map((p) => (
                          <span key={p.key} className="inline-flex rounded-full bg-muted px-2 py-0.5 text-[10px] text-muted-foreground">
                            {p.label}
                          </span>
                        ))}
                        {model.params.length > 5 && (
                          <span className="inline-flex rounded-full bg-muted px-2 py-0.5 text-[10px] text-muted-foreground">
                            +{model.params.length - 5}
                          </span>
                        )}
                      </div>

                      {/* 设为默认按钮 */}
                      <div className="flex gap-2 pt-1">
                        {model.category === "image" && (
                          <Button
                            variant={isImageDefault ? "secondary" : "outline"}
                            size="sm"
                            className="h-7 text-xs"
                            onClick={() => {
                              setTextToImageModel(model.id);
                              setImageToImageModel(model.id);
                            }}
                          >
                            {isImageDefault ? (
                              <><Check className="mr-1 h-3 w-3" /> 默认图片模型</>
                            ) : (
                              <>设为图片默认</>
                            )}
                          </Button>
                        )}
                        {model.category === "video" && (
                          <Button
                            variant={isVideoDefault ? "secondary" : "outline"}
                            size="sm"
                            className="h-7 text-xs"
                            onClick={() => {
                              setTextToVideoModel(model.id);
                              setImageToVideoModel(model.id);
                            }}
                          >
                            {isVideoDefault ? (
                              <><Check className="mr-1 h-3 w-3" /> 默认视频模型</>
                            ) : (
                              <>设为视频默认</>
                            )}
                          </Button>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          </TabsContent>
        </Tabs>
      </div>
    </AppShell>
  );
}

"use client";

import { useState, useCallback } from "react";
import { GenerationLayout } from "@/components/shared/GenerationLayout";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { useTaskStore, taskManager } from "@/stores/taskStore";
import { TaskListItem, TaskStats } from "@/components/shared/TaskList";
import { useConfig } from "@/hooks/useConfig";
import { cn } from "@/lib/utils";
import { agnes } from "@/services/agnes";
import {
  Video, Sparkles, Loader2, AlertCircle, RotateCcw, Trash2,
  Film, List, CheckCircle2, XCircle,
} from "lucide-react";
import { TaskMonitorPanel } from "@/components/shared/TaskMonitorPanel";
import Link from "next/link";
import { DynamicParamsPanel } from "@/components/shared/DynamicParamsPanel";

const DURATION_OPTIONS = [
  { value: 3, label: "3 秒" },
  { value: 5, label: "5 秒", badge: "推荐" },
  { value: 10, label: "10 秒" },
  { value: 15, label: "15 秒" },
];
const ASPECT_OPTIONS = [
  { value: "16:9", label: "横屏 16:9" },
  { value: "9:16", label: "竖屏 9:16" },
  { value: "1:1", label: "方形 1:1" },
];
const SUGGESTED_PROMPTS = [
  "夕阳下的海滩，海浪轻轻拍打着沙滩，慢动作",
  "赛博朋克城市夜景，霓虹灯光，雨滴坠落",
  "一只蝴蝶在花丛中翩翩起舞，微距摄影",
  "延时摄影：云海在山间流动，日出时刻",
];

async function downloadVideo(url: string, filename: string) {
  try {
    const r = await fetch(url);
    const b = await r.blob();
    const u = URL.createObjectURL(b);
    const a = document.createElement("a");
    a.href = u; a.download = filename; a.click();
    URL.revokeObjectURL(u);
  } catch { window.open(url, "_blank"); }
}

export default function TextToVideoPage() {
  const { isConfigured, textToVideoModel } = useConfig();
  const tasks = useTaskStore((s) => s.tasks);
  const addTask = useTaskStore((s) => s.addTask);
  const removeTask = useTaskStore((s) => s.removeTask);

  const [prompt, setPrompt] = useState("");
  const [duration, setDuration] = useState(5);
  const [aspectRatio, setAspectRatio] = useState("16:9");
  const [dynamicParams, setDynamicParams] = useState<Record<string, unknown>>({});
  const [error, setError] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const isPromptEmpty = prompt.trim().length === 0;
  const model = textToVideoModel || "agnes-video-v2.0";

  const videoTasks = tasks.filter((t) => t.type === "text-to-video");
  const completedTasks = videoTasks.filter((t) => t.status === "completed");
  const failedTasks = videoTasks.filter((t) => t.status === "failed" || t.status === "timeout");
  const activeTask = videoTasks.find((t) => ["queued", "processing", "uploading", "submitted"].includes(t.status));

  const getFrameParams = useCallback(() => {
    const [w, h] = aspectRatio === "16:9" ? [1152, 768] : aspectRatio === "9:16" ? [768, 1152] : [1024, 1024];
    const numFrames = Math.min(Math.max(Math.round(duration * 24), 9), 441);
    const adjustedFrames = Math.max(1, Math.round((numFrames - 1) / 8)) * 8 + 1;
    return { width: w, height: h, numFrames: adjustedFrames, frameRate: 24 };
  }, [duration, aspectRatio]);

  const handleGenerate = async () => {
    if (isPromptEmpty || isGenerating) return;
    setError(null);
    setIsGenerating(true);

    const frameParams = getFrameParams();
    const taskId = addTask({
      taskId: "", type: "text-to-video",
      model, prompt: prompt.trim(),
      status: "queued", progress: 0,
      resultUrl: "", thumbnail: "", errorMessage: "",
      params: { duration, aspectRatio, ...frameParams, ...dynamicParams },
    });

    try {
      await taskManager.execute(taskId, "text-to-video", () =>
        agnes.video.create({
          prompt: prompt.trim(),
          model,
          ...frameParams,
          ...dynamicParams,
        })
      );
    } catch (err) {
      setError(err instanceof Error ? err.message : "生成失败");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if ((e.ctrlKey || e.metaKey) && e.key === "Enter") { e.preventDefault(); handleGenerate(); }
  };

  const leftPanel = (
    <div className="space-y-6">
      {!isConfigured && (
        <Card className="border-amber-200 bg-amber-50">
          <CardContent className="flex items-start gap-3 p-4 text-sm">
            <AlertCircle className="mt-0.5 h-4 w-4 shrink-0 text-amber-600" />
            <div>
              <p className="font-medium text-amber-800">尚未配置 API</p>
              <p className="text-amber-700">请先在 <Link href="/settings" className="underline">API 配置</Link> 页面填写密钥。</p>
            </div>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardContent className="p-4 space-y-4">
          <div className="space-y-1.5">
            <Label>视频描述 Prompt</Label>
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="输入视频场景描述，比如：一只蝴蝶在花丛中飞翔..."
              rows={4}
              className="flex w-full rounded-lg border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground/60 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 resize-none"
              disabled={isGenerating}
            />
            <p className="text-xs text-muted-foreground/60">
              <kbd className="rounded border bg-muted px-1 py-0.5 text-[10px]">Ctrl+Enter</kbd> 快速生成
            </p>
            {!prompt && (
              <div className="flex flex-wrap gap-1.5 pt-1">
                {SUGGESTED_PROMPTS.map((sp, i) => (
                  <button key={i} type="button" onClick={() => setPrompt(sp)}
                    className="rounded-full border bg-muted/30 px-2.5 py-1 text-[11px] text-muted-foreground hover:bg-muted transition-colors">
                    {sp.slice(0, 20)}...
                  </button>
                ))}
              </div>
            )}
          </div>

          <div className="space-y-3">
            <Label>视频时长</Label>
            <div className="grid grid-cols-4 gap-2">
              {DURATION_OPTIONS.map((opt) => (
                <button key={opt.value} type="button" onClick={() => setDuration(opt.value)}
                  className={cn(
                    "rounded-lg border px-3 py-2 text-center text-xs transition-all",
                    duration === opt.value
                      ? "border-emerald-500 bg-emerald-50 ring-1 ring-emerald-500"
                      : "hover:border-muted-foreground/30"
                  )}>
                  <span className="font-medium">{opt.label}</span>
                  {opt.badge && <span className="block text-[9px] text-emerald-600 mt-0.5">{opt.badge}</span>}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <Label>画面比例</Label>
            <div className="grid grid-cols-3 gap-2">
              {ASPECT_OPTIONS.map((opt) => (
                <button key={opt.value} type="button" onClick={() => setAspectRatio(opt.value)}
                  className={cn(
                    "rounded-lg border px-3 py-2 text-center text-xs transition-all",
                    aspectRatio === opt.value
                      ? "border-emerald-500 bg-emerald-50 ring-1 ring-emerald-500"
                      : "hover:border-muted-foreground/30"
                  )}>
                  {opt.label}
                </button>
              ))}
            </div>
          </div>

          <DynamicParamsPanel
            modelId={model}
            values={dynamicParams}
            onChange={(k, v) => setDynamicParams((p) => ({ ...p, [k]: v }))}
          />

          <Button size="lg" className="w-full bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 text-base h-12 gap-2"
            onClick={handleGenerate} disabled={isPromptEmpty || isGenerating}>
            {isGenerating
              ? <><Loader2 className="h-5 w-5 animate-spin" /> 生成中...</>
              : <><Sparkles className="h-5 w-5" /> 生成视频</>}
          </Button>
        </CardContent>
      </Card>
    </div>
  );

  const rightPanel = (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <List className="h-5 w-5 text-muted-foreground" />
          <h2 className="font-semibold">视频任务</h2>
          {videoTasks.length > 0 && <span className="rounded-full bg-muted px-2 py-0.5 text-xs">{videoTasks.length}</span>}
        </div>
        <TaskStats tasks={videoTasks} />
      </div>

      {videoTasks.length === 0 ? (
        <Card className="min-h-[400px]">
          <CardContent className="flex flex-col items-center justify-center py-16 space-y-4">
            <div className="rounded-full bg-gradient-to-br from-emerald-100 to-teal-100 p-4">
              <Film className="h-10 w-10 text-emerald-400" />
            </div>
            <div className="text-center">
              <p className="font-medium text-muted-foreground">暂无任务</p>
              <p className="text-sm text-muted-foreground/60">输入描述后点击生成，任务会显示在这里</p>
            </div>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {videoTasks.map((task) => (
            <TaskListItem
              key={task.id}
              task={task}
              onDelete={removeTask}
              onDownload={(url) => downloadVideo(url, `agnes-video-${Date.now()}.mp4`)}
            />
          ))}
        </div>
      )}

      {error && (
        <Card className="border-red-200 bg-red-50">
          <CardContent className="flex items-start gap-3 p-4 text-sm">
            <AlertCircle className="mt-0.5 h-4 w-4 shrink-0 text-red-600" />
            <div><p className="font-medium text-red-800">生成失败</p><p className="text-red-700">{error}</p></div>
          </CardContent>
        </Card>
      )}
    </div>
  );

  return (
    <>
      <GenerationLayout
        icon={<Video className="h-6 w-6 text-white" />}
        title="文生视频"
        description="输入文字描述，AI 将为您生成动态视频"
        leftPanel={leftPanel}
        rightPanel={rightPanel}
        bgGradient="via-emerald-50/20"
      />
      <TaskMonitorPanel />
    </>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { VideoTask } from "@/hooks/useVideoTaskQueue";
import {
  Download, Loader2, AlertCircle, Trash2, Clock, Play,
  CheckCircle2, XCircle, X, ImageIcon,
} from "lucide-react";

function StatusBadge({ status }: { status: VideoTask["status"] }) {
  const config = {
    queued:     { label: "排队中", className: "bg-muted text-muted-foreground", icon: Loader2 },
    processing: { label: "生成中", className: "bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300", icon: Loader2 },
    completed:  { label: "已完成", className: "bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300", icon: CheckCircle2 },
    failed:     { label: "失败",   className: "bg-red-100 text-red-700 dark:bg-red-900 dark:text-red-300", icon: XCircle },
    cancelled:  { label: "已取消", className: "bg-gray-100 text-gray-700 dark:bg-gray-900 dark:text-gray-300", icon: XCircle },
    uploading:  { label: "上传中", className: "bg-yellow-100 text-yellow-700 dark:bg-yellow-900 dark:text-yellow-300", icon: Loader2 },
    submitted:  { label: "已提交", className: "bg-purple-100 text-purple-700 dark:bg-purple-900 dark:text-purple-300", icon: Loader2 },
    timeout:    { label: "超时",   className: "bg-orange-100 text-orange-700 dark:bg-orange-900 dark:text-orange-300", icon: XCircle },
  };
  const { label, className, icon: Icon } = config[status];
  return (
    <span className={cn("inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-medium", className)}>
      <Icon className={cn("h-3 w-3", status === "processing" && "animate-spin")} />
      {label}
    </span>
  );
}

interface TaskCardProps {
  task: VideoTask;
  onCancel: (id: string) => void;
  onRemove: (id: string) => void;
  onDownload: (url: string) => void;
}

export function TaskCard({ task, onCancel, onRemove, onDownload }: TaskCardProps) {
  const [showVideo, setShowVideo] = useState(task.status === "completed");
  useEffect(() => {
    if (task.status === "completed" && task.result?.url) setShowVideo(true);
  }, [task.status, task.result?.url]);
  const timeStr = new Date(task.createdAt).toLocaleTimeString("zh-CN", { hour: "2-digit", minute: "2-digit" });

  return (
    <div className={cn("rounded-xl border p-4 transition-all duration-200",
      task.status === "completed"  && "border-green-200 bg-green-50/30 dark:border-green-800 dark:bg-green-950/20",
      task.status === "failed"     && "border-red-200 bg-red-50/30 dark:border-red-800 dark:bg-red-950/20",
      task.status === "processing" && "border-blue-200 bg-blue-50/30 dark:border-blue-800 dark:bg-blue-950/20",
      task.status === "queued"     && "border-muted bg-muted/30",
    )}>
      <div className="flex items-start justify-between gap-3">
        <div className="flex-1 min-w-0 space-y-1">
          <div className="flex items-center gap-2">
            <span className="text-xs text-muted-foreground">{timeStr}</span>
            {task.type === "image-to-video" && <span className="text-[10px] text-muted-foreground/60 rounded-full border px-1.5 py-0">图生视频</span>}
            <StatusBadge status={task.status} />
          </div>
          {task.prompt && <p className="text-sm text-foreground/80 line-clamp-2">{task.prompt}</p>}
        </div>
        <div className="flex shrink-0 gap-1">
          {task.status === "processing" && (
            <Button variant="ghost" size="sm" onClick={() => onCancel(task.id)} disabled={task.cancelling}
              className="h-7 px-2 text-xs text-muted-foreground hover:text-destructive">
              {task.cancelling ? <Loader2 className="h-3 w-3 animate-spin" /> : <X className="h-3 w-3" />}取消
            </Button>
          )}
          <Button variant="ghost" size="sm" onClick={() => onRemove(task.id)}
            className="h-7 px-2 text-xs text-muted-foreground hover:text-destructive">
            <Trash2 className="h-3 w-3" />
          </Button>
        </div>
      </div>

      {(task.status === "processing" || task.status === "queued") && (
        <div className="mt-3 space-y-1.5">
          <div className="flex items-center justify-between text-xs">
            <span className="text-blue-600 dark:text-blue-400">{task.status === "queued" ? "等待处理" : "正在生成视频..."}</span>
            <span className="text-muted-foreground">{task.progress}%</span>
          </div>
          <div className="h-2 w-full overflow-hidden rounded-full bg-blue-100 dark:bg-blue-950">
            <div className={cn("h-full rounded-full transition-all duration-500 ease-out",
              task.status === "queued" ? "w-full animate-pulse bg-muted-foreground/30" : "bg-gradient-to-r from-blue-500 to-cyan-500"
            )} style={{ width: task.progress + "%" }} />
          </div>
        </div>
      )}

      {task.type === "image-to-video" && task.sourcePreview && task.status !== "queued" && (
        <div className="mt-3 flex items-center gap-3 rounded-lg bg-muted/30 p-2">
          <div className="shrink-0 h-14 w-14 rounded-lg overflow-hidden bg-muted">
            <img src={task.sourcePreview} alt="首帧" className="h-full w-full object-cover" />
          </div>
          <div className="text-xs text-muted-foreground">
            <span className="flex items-center gap-1"><ImageIcon className="h-3 w-3" />首帧图片</span>
          </div>
        </div>
      )}

      {task.status === "completed" && task.result && (
        <div className="mt-3 space-y-3">
          {showVideo ? (
            <div className="rounded-lg overflow-hidden bg-black">
              <video src={task.result.url} controls autoPlay muted className="w-full max-h-[300px]">您的浏览器不支持视频播放</video>
            </div>
          ) : (
            <div onClick={() => setShowVideo(true)}
              className="relative flex cursor-pointer items-center justify-center rounded-lg bg-gradient-to-br from-emerald-50 to-teal-50 dark:from-emerald-950/50 dark:to-teal-950/50 h-32 group">
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="rounded-full bg-white/90 p-3 shadow-lg transition-transform duration-200 group-hover:scale-110">
                  <Play className="h-5 w-5 text-emerald-600 fill-emerald-600" />
                </div>
              </div>
              <span className="text-xs text-muted-foreground absolute bottom-2">点击播放</span>
            </div>
          )}
          <div className="flex gap-2">
            <Button size="sm" variant="outline" onClick={() => onDownload(task.result!.url)}>
              <Download className="mr-1 h-3.5 w-3.5" />下载 MP4
            </Button>
            {!showVideo && <Button size="sm" variant="ghost" onClick={() => setShowVideo(true)}>
              <Play className="mr-1 h-3.5 w-3.5" />播放
            </Button>}
          </div>
        </div>
      )}

      {task.status === "failed" && task.error && (
        <div className="mt-3 flex items-start gap-2 rounded-md bg-red-50 p-2.5 text-xs text-red-700 dark:bg-red-950 dark:text-red-300">
          <AlertCircle className="mt-0.5 h-3 w-3 shrink-0" />
          <span>{task.error}</span>
        </div>
      )}
    </div>
  );
}

﻿"use client";
import { useState, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { useTranslation } from "@/i18n";
import { Film, Download, Upload, GripVertical } from "lucide-react";

interface TimelineImportProps {
  videoCount: number;
  lockedCount: number;
  selectedCount: number;
  onImportAll: () => void;
  onImportSelected: () => void;
  onImportLocked: () => void;
  onImportScene: (sceneId: string) => void;
  onImportShot: (shotId: string) => void;
  sceneIds: string[];
  shotIds: string[];
}

export function TimelineImport({
  videoCount, lockedCount, selectedCount,
  onImportAll, onImportSelected, onImportLocked,
  onImportScene, onImportShot,
  sceneIds, shotIds,
}: TimelineImportProps) {
  const { t } = useTranslation();
  const [isDragOver, setIsDragOver] = useState(false);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(true);
  }, []);

  const handleDragLeave = useCallback(() => {
    setIsDragOver(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    onImportAll();
  }, [onImportAll]);

  return (
    <Card>
      <CardHeader className="pb-2">
        <CardTitle className="flex items-center gap-2 text-base">
          <Film className="h-4 w-4" />
          {t("pipeline.timelineImport")}
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-3">
        {/* Drop zone */}
        <div
          className={`rounded-lg border-2 border-dashed p-4 text-center transition-colors cursor-pointer ${
            isDragOver ? "border-primary bg-primary/5" : "border-border hover:border-primary/50"
          }`}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          <Upload className="h-5 w-5 mx-auto mb-1 text-muted-foreground" />
          <p className="text-xs text-muted-foreground">{t("pipeline.dragImport")}</p>
          <p className="text-[10px] text-muted-foreground/60 mt-0.5">
            {videoCount} {t("pipeline.videos")} / {lockedCount} {t("pipeline.statusLocked")}
          </p>
        </div>

        {/* Import buttons */}
        <div className="flex flex-wrap gap-1.5">
          <Button variant="outline" size="sm" className="h-7 text-[11px]" onClick={onImportAll} disabled={videoCount === 0}>
            <Download className="h-3.5 w-3.5 mr-1" />{t("pipeline.importAllVideos")}
          </Button>
          <Button variant="outline" size="sm" className="h-7 text-[11px]" onClick={onImportSelected} disabled={selectedCount === 0}>
            <Download className="h-3.5 w-3.5 mr-1" />{t("pipeline.importSelected")}
          </Button>
          <Button variant="outline" size="sm" className="h-7 text-[11px]" onClick={onImportLocked} disabled={lockedCount === 0}>
            <Download className="h-3.5 w-3.5 mr-1" />{t("pipeline.importLocked")}
          </Button>
        </div>

        {/* Scene/Shot quick import */}
        {sceneIds.length > 0 && (
          <div className="space-y-1">
            <p className="text-[10px] font-medium text-muted-foreground">{t("pipeline.importCurrentScene")}</p>
            <div className="flex flex-wrap gap-1">
              {sceneIds.slice(0, 5).map((sid) => (
                <Button key={sid} variant="ghost" size="sm" className="h-5 text-[10px]" onClick={() => onImportScene(sid)}>
                  {sid.slice(-6)}
                </Button>
              ))}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

"use client";
import { useTranslation } from "@/i18n";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Star, Copy, Play, MoreHorizontal, Clock } from "lucide-react";
import type { PromptTemplate } from "@/types";
import { cn } from "@/lib/utils";

interface PromptCardProps {
  prompt: PromptTemplate;
  onSelect?: (prompt: PromptTemplate) => void;
  onFavorite?: (id: string) => void;
  onClone?: (id: string) => void;
  className?: string;
}

export function PromptCard({ prompt, onSelect, onFavorite, onClone, className }: PromptCardProps) {
  const { t } = useTranslation();
  return (
    <Card className={cn("group relative overflow-hidden border-white/5 bg-white/[0.03] backdrop-blur-xl hover:bg-white/[0.06] transition-all duration-300", className)}>
      <div className="absolute inset-0 bg-gradient-to-br from-purple-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
      <div className="relative p-5 space-y-3">
        <div className="flex items-start justify-between gap-2">
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold text-sm truncate">{prompt.name}</h3>
              {prompt.isFavorite && <Star className="h-3.5 w-3.5 fill-yellow-400 text-yellow-400 shrink-0" />}
            </div>
            <Badge variant="secondary" className="text-[10px] px-1.5 py-0 h-4">{t("prompt.categories." + prompt.category) || prompt.category}</Badge>
          </div>
          <div className="flex gap-1 shrink-0">
            {onFavorite && (
              <Button variant="ghost" size="icon" className="h-7 w-7" onClick={(e) => { e.stopPropagation(); onFavorite(prompt.id); }}>
                <Star className={cn("h-3.5 w-3.5", prompt.isFavorite && "fill-yellow-400 text-yellow-400")} />
              </Button>
            )}
            {onClone && (
              <Button variant="ghost" size="icon" className="h-7 w-7 opacity-0 group-hover:opacity-100 transition-opacity" onClick={(e) => { e.stopPropagation(); onClone(prompt.id); }}>
                <Copy className="h-3.5 w-3.5" />
              </Button>
