import type { PromptTemplate } from "@/types";

export function usePromptRenderer(template: PromptTemplate | null, variables: Record<string, string>) {
  const extractedVars = useMemo(() => template ? extractVariables(template.content) : [], [template?.content]);
  const rendered = useMemo(() => template ? renderPrompt(template.content, variables) : "", [template?.content, variables]);
  const missingVars = useMemo(() => extractedVars.filter((v) => !variables[v]?.trim()), [extractedVars, variables]);
  return { rendered, missingVars, extractedVars, isValid: missingVars.length === 0 };
}

import { useState, useMemo } from "react";

export function useSearch<T>(items: T[], searchFields: (keyof T)[], query: string) {
  return useMemo(() => {
    if (!query.trim()) return items;
    const q = query.toLowerCase();
    return items.filter((item) => searchFields.some((field) => {
      const val = item[field];
      return typeof val === "string" && val.toLowerCase().includes(q);
    }));
  }, [items, searchFields, query]);
}

// ============================================================
// useTaskManager — 统一任务管理 Hook
// ============================================================
// 供各个页面使用，封装了 TaskStore + TaskManager 的操作
// ============================================================

"use client";

import { useCallback, useRef } from "react";
import { useTaskStore, type UnifiedTask, type TaskType } from "@/stores/taskStore";
import { taskManager } from "@/services/taskManager";
import { useConfig } from "./useConfig";

export function useTaskManager() {
  const tasks = useTaskStore((s) => s.tasks);
  const updateTask = useTaskStore((s) => s.updateTask);
  const removeTask = useTaskStore((s) => s.removeTask);
  const clearCompleted = useTaskStore((s) => s.clearCompleted);
  const clearAll = useTaskStore((s) => s.clearAll);

  const { textToImageModel, imageToImageModel, textToVideoModel, imageToVideoModel } = useConfig();

  const activeTasks = tasks.filter(
    (t) => t.status === "processing" || t.status === "queued"
  );
  const completedTasks = tasks.filter((t) => t.status === "completed");
  const failedTasks = tasks.filter((t) => t.status === "failed" || t.status === "cancelled");

  /**
   * 创建图片生成任务（文生图）
   */
  const createImageTask = useCallback(
    async (params: {
      prompt: string;
      size?: string;
      n?: number;
      model?: string;
      params?: Record<string, unknown>;
    }): Promise<UnifiedTask> => {
      return taskManager.createTask({
        type: "text-to-image",
        model: params.model || textToImageModel || "agnes-image-2.1-flash",
        prompt: params.prompt,
        params: { ...params.params, size: params.size, n: params.n },
      });
    },
    [textToImageModel]
  );

  /**
   * 创建视频生成任务（文生视频）
   */
  const createVideoTask = useCallback(
    async (params: {
      prompt: string;
      duration?: number;
      fps?: number;
      aspectRatio?: string;
      model?: string;
      extraParams?: Record<string, unknown>;
    }): Promise<UnifiedTask> => {
      return taskManager.createTask({
        type: "text-to-video",
        model: params.model || textToVideoModel || "agnes-video-v2.0",
        prompt: params.prompt,
        params: {
          duration: params.duration,
          fps: params.fps,
          aspect_ratio: params.aspectRatio,
          ...params.extraParams,
        },
      });
    },
    [textToVideoModel]
  );

  /**
   * 取消任务
   */
  const cancelTask = useCallback((id: string) => {
    taskManager.cancelTask(id);
  }, []);

  /**
   * 重试任务
   */
  const retryTask = useCallback(
    async (id: string): Promise<UnifiedTask | null> => {
      return taskManager.retryTask(id);
    },
    []
  );

  /**
   * 删除任务记录
   */
  const deleteTask = useCallback(
    (id: string) => {
      taskManager.cancelTask(id);
      removeTask(id);
    },
    [removeTask]
  );

  return {
    tasks,
    activeTasks,
    completedTasks,
    failedTasks,
    activeCount: activeTasks.length,
    createImageTask,
    createVideoTask,
    cancelTask,
    retryTask,
    deleteTask,
    clearCompleted,
    clearAll,
    updateTask,
  };
}

"use client";

import { useState, useCallback, useRef, useEffect } from "react";
import { agnes, AgnesApiError } from "@/services/agnes";
import { useTaskStore } from "@/stores/taskStore";
import { useConfigStore } from "@/stores/configStore";
import { ErrorClassifier, AgnesErrorType, MAX_RETRIES } from "@/services/errorClassifier";
import type { VideoResult, TextToVideoParams, ImageToVideoParams } from "@/services/agnes";

// ============================================================
// 类型定义
// ============================================================

export type VideoTaskStatus =
  | "queued"      // 等待中
  | "uploading"   // 上传中
  | "submitted"   // 已提交
  | "processing"  // 处理中
  | "completed"   // 已完成
  | "failed"      // 失败
  | "timeout"     // 超时
  | "cancelled";  // 已取消

export interface VideoTask {
  id: string;
  taskId: string;
  type: "text-to-video" | "image-to-video";
  prompt: string;
  sourcePreview?: string;
  numFrames?: number;
  frameRate?: number;
  status: VideoTaskStatus;
  progress: number;
  result?: VideoResult;
  error?: string;
  errorType?: AgnesErrorType;
  createdAt: number;
  updatedAt: number;
  cancelling?: boolean;
  retryCount: number;
  duration?: number;
}

// ============================================================
// 持久化
// ============================================================

const STORAGE_KEY = "agnes-video-tasks";
const TASK_TTL = 24 * 60 * 60 * 1000; // 24小时

function saveTasks(tasks: VideoTask[]): void {
  if (typeof window === "undefined") return;
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks)); }
  catch { /* quota exceeded */ }
}

function loadTasks(): VideoTask[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return [];
    const tasks: VideoTask[] = JSON.parse(raw);
    const now = Date.now();
    return tasks.filter(t => now - t.createdAt < TASK_TTL);
  } catch { return []; }
}

// ============================================================
// Hook
// ============================================================

export function useVideoTaskQueue() {
  const [tasks, setTasks] = useState<VideoTask[]>(() => loadTasks());
  const abortMap = useRef<Map<string, AbortController>>(new Map());
  const tasksRef = useRef<VideoTask[]>([]);
  const pollTimers = useRef<Map<string, ReturnType<typeof setInterval>>>(new Map());

  // 保持 ref 同步
  useEffect(() => { tasksRef.current = tasks; }, [tasks]);

  // 自动持久化
  useEffect(() => { saveTasks(tasks); }, [tasks]);

  // 页面关闭时自动保存
  useEffect(() => {
    const handle = () => saveTasks(tasksRef.current);
    window.addEventListener("beforeunload", handle);
    return () => window.removeEventListener("beforeunload", handle);
  }, []);

  const updateTask = useCallback((id: string, patch: Partial<VideoTask>) => {
    setTasks((prev) => {
      const next = prev.map((t) =>
        t.id === id ? { ...t, ...patch, updatedAt: Date.now() } : t
      );
      tasksRef.current = next;
      return next;
    });
  }, []);

  const generateId = useCallback(
    () => `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    []
  );

  // ==========================================================
  // 智能轮询：每5秒一次，最长15分钟
  // ==========================================================
  const startPolling = useCallback((id: string, apiTaskId: string, taskType: "text-to-video" | "image-to-video") => {
    // 停止已有轮询
    const existing = pollTimers.current.get(id);
    if (existing) clearInterval(existing);

    const startTime = Date.now();
    const MAX_POLL_TIME = 15 * 60 * 1000; // 15分钟
    const POLL_INTERVAL = 5000; // 5秒

    const poll = async () => {
      const elapsed = Date.now() - startTime;
      if (elapsed > MAX_POLL_TIME) {
        clearInterval(pollTimers.current.get(id));
        pollTimers.current.delete(id);
        updateTask(id, { status: "timeout", error: "生成超时，请重新尝试", progress: 0 });
        abortMap.current.get(id)?.abort();
        return;
      }

      try {
        const progress = await agnes.video.getProgress(apiTaskId);
        updateTask(id, { status: progress.status as VideoTaskStatus, progress: progress.progress });

        if (progress.status === "completed") {
          clearInterval(pollTimers.current.get(id));
          pollTimers.current.delete(id);
          if (progress.result?.url) {
            updateTask(id, { status: "completed", progress: 100, result: progress.result });
            const t = tasksRef.current.find(x => x.id === id);
            if (t) {
              useTaskStore.getState().addTask({
                id: t.id, taskId: apiTaskId, type: t.type,
                model: useConfigStore.getState().model || "agnes-video-v2.0",
                prompt: t.prompt, status: "completed", progress: 100,
                resultUrl: progress.result.url, thumbnail: t.sourcePreview || "",
                errorMessage: "", params: {}, duration: progress.result.duration,
              });
            }
          } else {
            // status completed but no URL, keep polling
            updateTask(id, { status: "processing" });
          }
        } else if (progress.status === "failed") {
          clearInterval(pollTimers.current.get(id));
          pollTimers.current.delete(id);
          updateTask(id, { status: "failed", error: "视频生成失败" });
        }
      } catch (err) {
        const classified = ErrorClassifier.classify(err);
        // 连续错误不停止轮询，只是记录
        console.debug("[Poll] 查询失败:", classified.message);
      }
    };

    // 立即执行一次，然后每5秒执行
    poll();
    const timer = setInterval(poll, POLL_INTERVAL);
    pollTimers.current.set(id, timer);
  }, [updateTask]);

  const stopPolling = useCallback((id: string) => {
    const timer = pollTimers.current.get(id);
    if (timer) { clearInterval(timer); pollTimers.current.delete(id); }
  }, []);

  // ==========================================================
  // 安全重试逻辑
  // ==========================================================
  const executeWithRetry = useCallback(async (
    id: string,
    action: () => Promise<{ taskId: string; videoId: string }>,
    taskType: "text-to-video" | "image-to-video"
  ): Promise<{ taskId: string; videoId: string }> => {
    let lastError: unknown;
    let retryCount = 0;

    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
      try {
        if (attempt > 0) {
          const delay = ErrorClassifier.getRetryDelay(attempt - 1);
          console.debug(`[Retry] 第 ${attempt} 次重试，等待 ${delay}ms`);
          await new Promise(r => setTimeout(r, delay));
        }
        return await action();
      } catch (err) {
        lastError = err;
        const classified = ErrorClassifier.classify(err);
        retryCount = attempt + 1;
        updateTask(id, { retryCount });

        if (!classified.retryable || attempt >= MAX_RETRIES) {
          throw err;
        }
        console.debug(`[Retry] 可重试错误 (${classified.type})，第 ${attempt + 1}/${MAX_RETRIES} 次`);
      }
    }
    throw lastError;
  }, [updateTask]);

  // ==========================================================
  // 通用任务执行
  // ==========================================================
  const executeTask = useCallback(async (
    id: string,
    creator: () => Promise<{ taskId: string; videoId: string; numericId: string; syncUrl: string }>,
    taskType: "text-to-video" | "image-to-video"
  ) => {
    const controller = new AbortController();
    abortMap.current.set(id, controller);

    try {
      // Step 1: 立即显示提交中
      updateTask(id, { status: "submitted" });

      // Step 2: 提交到 API（带60秒超时，支持重试）
      const result = await executeWithRetry(id, async () => {
        const timeoutPromise = new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error(`TIMEOUT: 创建任务超时 (60s)`)), 60000)
        );
        const r = await Promise.race([creator(), timeoutPromise]);
        if (!r.taskId) throw new Error("API未返回任务ID");
        return { taskId: r.taskId, videoId: r.videoId || r.taskId };
      }, taskType);

      const { taskId, videoId } = result;

      // Step 3: 同步结果（如果有）
      if (result.taskId === "sync") {
        updateTask(id, { status: "completed", progress: 100 });
        return;
      }

      // Step 4: 开始轮询
      updateTask(id, { taskId: videoId, status: "processing" });
      startPolling(id, videoId, taskType);

      // 等待轮询完成或失败
      await new Promise<void>((resolve) => {
        const checkStatus = setInterval(() => {
          const t = tasksRef.current.find(x => x.id === id);
          if (!t || ["completed", "failed", "timeout", "cancelled"].includes(t.status)) {
            clearInterval(checkStatus);
            resolve();
          }
        }, 1000);
      });

    } catch (err) {
      const classified = ErrorClassifier.classify(err);
      updateTask(id, {
        status: classified.type === AgnesErrorType.TIMEOUT ? "timeout" : "failed",
        error: classified.userMessage,
        errorType: classified.type,
        progress: 0,
      });

      // 保存失败到 TaskStore
      const t = tasksRef.current.find(x => x.id === id);
      if (t) {
        useTaskStore.getState().addTask({
          id: t.id, taskId: t.taskId || "", type: t.type,
          model: useConfigStore.getState().model || "agnes-video-v2.0",
          prompt: t.prompt, status: "failed", progress: 0,
          resultUrl: "", thumbnail: t.sourcePreview || "",
          errorMessage: classified.userMessage, params: {},
        });
      }
    } finally {
      stopPolling(id);
      abortMap.current.delete(id);
    }
  }, [updateTask, executeWithRetry, startPolling, stopPolling]);

  // ==========================================================
  // 文生视频
  // ==========================================================
  const addTask = useCallback(async (params: TextToVideoParams) => {
    const id = generateId();
    const task: VideoTask = {
      id, taskId: "", type: "text-to-video",
      prompt: params.prompt, numFrames: params.numFrames ?? 121,
      frameRate: params.frameRate ?? 24, status: "queued", progress: 0,
      createdAt: Date.now(), updatedAt: Date.now(), retryCount: 0,
    };
    setTasks((prev) => [task, ...prev]);

    await executeTask(
      id,
      () => agnes.video.create(params),
      "text-to-video"
    );
  }, [generateId, executeTask]);

  // ==========================================================
  // 图生视频
  // ==========================================================
  const addImageTask = useCallback(async (
    params: ImageToVideoParams & { sourcePreview?: string }
  ) => {
    const id = generateId();
    const task: VideoTask = {
      id, taskId: "", type: "image-to-video",
      prompt: params.prompt ?? "", sourcePreview: params.sourcePreview,
      status: "uploading", progress: 0,
      createdAt: Date.now(), updatedAt: Date.now(), retryCount: 0,
    };
    setTasks((prev) => [task, ...prev]);

    await executeTask(
      id,
      () => agnes.video.createFromImage({ image: params.image, prompt: params.prompt }),
      "image-to-video"
    );
  }, [generateId, executeTask]);

  // ==========================================================
  // 取消 / 删除 / 清除
  // ==========================================================
  const cancelTask = useCallback((id: string) => {
    stopPolling(id);
    abortMap.current.get(id)?.abort();
    updateTask(id, { status: "cancelled", cancelling: false });
  }, [updateTask, stopPolling]);

  const removeTask = useCallback((id: string) => {
    stopPolling(id);
    abortMap.current.get(id)?.abort();
    abortMap.current.delete(id);
    setTasks((prev) => prev.filter((t) => t.id !== id));
  }, [stopPolling]);

  const clearCompleted = useCallback(() => {
    setTasks((prev) =>
      prev.filter((t) =>
        ["queued", "uploading", "submitted", "processing"].includes(t.status)
      )
    );
  }, []);

  const clearAll = useCallback(() => {
    abortMap.current.forEach((c) => c.abort());
    abortMap.current.clear();
    pollTimers.current.forEach((t) => clearInterval(t));
    pollTimers.current.clear();
    setTasks([]);
  }, []);

  // 清理定时器
  useEffect(() => {
    return () => {
      pollTimers.current.forEach((t) => clearInterval(t));
      pollTimers.current.clear();
    };
  }, []);

  const activeTask = tasks.find(
    (t) => ["queued", "uploading", "submitted", "processing"].includes(t.status)
  ) ?? null;

  return {
    tasks,
    activeTask,
    addTask,
    addImageTask,
    cancelTask,
    removeTask,
    clearCompleted,
    clearAll,
  };
}

﻿"use client";
import React, { createContext, useContext, useState, useEffect, useCallback } from "react";
import zhDict from "./zh-CN";
import enDict from "./en-US";

export type Language = "zh-CN" | "en-US";

export interface Translations {
  [key: string]: string | Translations;
}

interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: string, params?: Record<string, string | number>) => string;
}

const STORAGE_KEY = "agnes_language";

const DICTS: Record<Language, Record<string, any>> = {
  "zh-CN": zhDict,
  "en-US": enDict,
};

function resolveValue(dict: Record<string, any>, key: string): string | null {
  // Try direct lookup first (for flat keys like "menu.home")
  if (key in dict && typeof dict[key] === "string") {
    return dict[key];
  }
  // Fall back to nested traversal (for dotted keys like "prompt.categories.general")
  const parts = key.split(".");
  let val: any = dict;
  for (const p of parts) {
    if (val && typeof val === "object" && p in val) {
      val = val[p];
    } else {
      return null;
    }
  }
  return typeof val === "string" ? val : null;
}

const LanguageContext = createContext<LanguageContextType>({
  language: "zh-CN",
  setLanguage: () => {},
  t: (key: string, params?: Record<string, string | number>) => {
    const val = resolveValue(DICTS["zh-CN"], key);
    let result = val ?? key;
    if (params) {
      for (const [k, v] of Object.entries(params)) {
        result = result.replace("{" + k + "}", String(v));
      }
    }
    return result;
  },
});

export function getBrowserLanguage(): Language {
  if (typeof window === "undefined") return "zh-CN";
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored === "zh-CN" || stored === "en-US") return stored;
  } catch (_e) { /* ignore */ }
  return "zh-CN";
}

export function LanguageProvider({ children }: { children: React.ReactNode }) {
  const [language, setLanguageState] = useState<Language>("zh-CN");

  useEffect(() => {
    setLanguageState(getBrowserLanguage());
  }, []);

  const setLanguage = useCallback((lang: Language) => {
    setLanguageState(lang);
    try {
      localStorage.setItem(STORAGE_KEY, lang);
    } catch (_e) { /* ignore */ }
  }, []);

  const t = useCallback(
    (key: string, params?: Record<string, string | number>): string => {
      const dict = DICTS[language];
      let result = resolveValue(dict, key) ?? key;
      if (params) {
        for (const [k, v] of Object.entries(params)) {
          result = result.replace("{" + k + "}", String(v));
        }
      }
      return result;
    },
    [language]
  );

  return React.createElement(LanguageContext.Provider, { value: { language, setLanguage, t } }, children);
}

export function useLanguage() {
  return useContext(LanguageContext);
}



export function useTranslation() {
  const { t, language } = useContext(LanguageContext);
  return { t, language };
}

﻿import type { Shot, Scene, Character, PromptPack } from "@/types";

/**
 * Generate a PromptPack for a given shot, injecting Character DNA and style.
 */
export function generatePromptPack(
  shot: Shot,
  scene: Scene,
  characters: Character[],
  styleDna: string,
): PromptPack {
  // Gather Character DNA blocks for characters in this shot
  const shotCharacterIds = Array.isArray(shot.characterIds) ? shot.characterIds : [];
  const sceneCharacterIds = Array.isArray(scene.characterIds) ? scene.characterIds : [];
  const activeCharacterIds = shotCharacterIds.length > 0 ? shotCharacterIds : sceneCharacterIds;
  const shotCharacters = activeCharacterIds.length > 0
    ? characters.filter((c) => activeCharacterIds.includes(c.id))
    : characters;
  const characterDna = shotCharacters.map((c) => c.dnaBlock || c.prompt).filter(Boolean).join("; ");
  const basePrompt = shot.description || shot.prompt || shot.title || scene.description || scene.title || "";

  // Build image prompt
  const imageParts: string[] = [basePrompt];
  if (characterDna) imageParts.push(characterDna);
  if (styleDna) imageParts.push(styleDna);
  const imagePrompt = imageParts.join(", ");

  // Build video prompt (slightly different for motion)
  const videoParts: string[] = [basePrompt];
  if (characterDna) videoParts.push(characterDna);
  if (styleDna) videoParts.push(styleDna);
  videoParts.push("cinematic, motion");
  const videoPrompt = videoParts.join(", ");

  // Negative prompt
  const negativeParts: string[] = [
    "blurry, low quality, distorted, deformed",
    "ugly, bad anatomy, bad proportions",
    "extra limbs, cloned face, disfigured",
    "grainy, noisy, dark, overexposed",
  ];
  if (shot.negativePrompt) negativeParts.push(shot.negativePrompt);
  const negativePrompt = negativeParts.join(", ");

  return { shotId: shot.id, imagePrompt, videoPrompt, negativePrompt, characterDna, styleDna };
}

/**
 * Generate prompt packs for all shots in a project.
 */
export function generateAllPromptPacks(
  scenes: Scene[],
  characters: Character[],
  styleDna: string,
): PromptPack[] {
  const packs: PromptPack[] = [];
  for (const scene of scenes) {
    for (const shot of scene.shots) {
      packs.push(generatePromptPack(shot, scene, characters, styleDna));
    }
  }
  return packs;
}

/**
 * Extract scene and shot structure from a story text using simple NLP.
 * This generates a structured storyboard from raw text.
 */
export function parseStoryToScenes(story: string, locale: "zh-CN" | "en-US" = "en-US"): Array<{
  title: string;
  description: string;
  cameraAngle?: string;
  shots: Array<{ title: string; description: string; order: number }>;
}> {
  const sentences = story
    .split(/[.!?\n]+/)
    .map((s) => s.trim())
    .filter((s) => s.length > 10);

  // Group sentences into scenes (every 1-3 sentences)
  const scenes: Array<{
    title: string;
    description: string;
    cameraAngle?: string;
    shots: Array<{ title: string; description: string; order: number }>;
  }> = [];

  const cameraAngles = ["wide shot", "medium shot", "close up", "extreme close up", "over the shoulder", "low angle", "high angle", "aerial view"];

  let sceneIdx = 0;
  for (let i = 0; i < sentences.length; i += Math.max(1, Math.floor(Math.random() * 3) + 1)) {
    sceneIdx++;
    const group = sentences.slice(i, i + 3);
    if (group.length === 0) continue;

    const sceneTitle = (locale === "zh-CN" ? "场景 " : "Scene ") + sceneIdx + ": " + group[0].substring(0, 40);
    const sceneDesc = group.join(". ");

    // Create 1-3 shots per scene
    const shots: Array<{ title: string; description: string; order: number }> = [];
    for (let j = 0; j < Math.min(group.length, 3); j++) {
      const angle = cameraAngles[Math.floor(Math.random() * cameraAngles.length)];
      shots.push({
        title: (locale === "zh-CN" ? "镜头 " : "Shot ") + (j + 1) + ": " + group[j].substring(0, 30) + "...",
        description: group[j],
        order: j + 1,
      });
    }

    scenes.push({
      title: sceneTitle,
      description: sceneDesc,
      cameraAngle: cameraAngles[Math.floor(Math.random() * cameraAngles.length)],
      shots,
    });
  }

  // Ensure 5-20 scenes
  while (scenes.length < 5 && sentences.length > 0) {
    const idx = scenes.length % sentences.length;
    const sentence = sentences[idx];
    scenes.push({
      title: (locale === "zh-CN" ? "场景 " : "Scene ") + (scenes.length + 1) + ": " + sentence.substring(0, 40) + "..." ,
      description: sentence,
      cameraAngle: cameraAngles[Math.floor(Math.random() * cameraAngles.length)],
      shots: [{
        title: (locale === "zh-CN" ? "镜头 1: " : "Shot 1: ") + sentence.substring(0, 30) + "...",
        description: sentence,
        order: 1,
      }],
    });
  }

  return scenes.slice(0, 20);
}

// ========== BackupService — V2.8 ==========
// 项目备份：导出 .project.json，包含所有关键数据

import { useProjectStore } from "@/stores/projectStore";
import { useProductionQueue } from "@/stores/productionQueueStore";
import { useEditorStore } from "@/stores/editorStore";
import { usePromptHistoryStore } from "@/stores/promptHistoryStore";
import { AssetsDB, type AssetRecord } from "./AssetsDB";
import { logger } from "@/lib/logger";

export type ProjectBackupAsset = AssetRecord & {
  dataUrl?: string;
};

export interface ProjectBackup {
  version: "2.8";
  exportedAt: number;
  project: {
    id: string;
    name: string;
    description: string;
    tags: string[];
    styleDna: string;
    lockedCharacterIds: string[];
    scenes: any[];
    storyScript?: string;
    createdAt: number;
    updatedAt: number;
  };
  productionQueue: any[];
  timeline: any[];
  promptHistory: Record<string, any[]>;
  assets: ProjectBackupAsset[];
}

const BACKUP_PREFIX = "agnes-backup-";
const MAX_AUTO_BACKUPS = 7;

function storeNameForAsset(type: AssetRecord["type"]): "images" | "videos" | "thumbnails" {
  return type === "video" ? "videos" : type === "thumbnail" ? "thumbnails" : "images";
}

async function blobToDataUrl(blob: Blob): Promise<string> {
  const buffer = await blob.arrayBuffer();
  const bytes = new Uint8Array(buffer);
  let binary = "";
  for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]);
  const base64 = btoa(binary);
  return `data:${blob.type || "application/octet-stream"};base64,${base64}`;
}

async function collectProjectAssets(projectId: string): Promise<ProjectBackupAsset[]> {
  const assets = await AssetsDB.queryMeta("projectId", projectId);
  const backupAssets: ProjectBackupAsset[] = [];
  for (const asset of assets) {
    try {
      const blob = await AssetsDB.load(storeNameForAsset(asset.type), asset.id);
      backupAssets.push(blob ? { ...asset, dataUrl: await blobToDataUrl(blob) } : asset);
    } catch (err) {
      logger.warn("Backup", "资产二进制导出失败，仅保留 metadata", { id: asset.id, error: String(err) });
      backupAssets.push(asset);
    }
  }
  return backupAssets;
}

/** 生成备份文件名 */
export function generateBackupFilename(projectId: string): string {
  return `${BACKUP_PREFIX}${projectId}-${Date.now()}.project.json`;
}

/** 导出完整项目备份 */
export async function exportBackup(projectId: string): Promise<{ success: boolean; data?: ProjectBackup; error?: string }> {
  try {
    const project = useProjectStore.getState().projects.find(p => p.id === projectId);
    if (!project) return { success: false, error: "项目不存在" };

    const queueItems = useProductionQueue.getState().items.filter(i => i.projectId === projectId);
    const editorState = useEditorStore.getState();
    const promptHistory = usePromptHistoryStore.getState().history;
    const assets = await collectProjectAssets(projectId);
    const timelines = editorState.timelines.filter(t => t.projectId === projectId);

    const backup: ProjectBackup = {
      version: "2.8",
      exportedAt: Date.now(),
      project: {
        id: project.id,
        name: project.name,
        description: project.description,
        tags: project.tags,
        styleDna: project.styleDna || "",
        lockedCharacterIds: project.lockedCharacterIds || [],
        scenes: project.scenes || [],
        storyScript: project.storyScript || "",
        createdAt: project.createdAt,
        updatedAt: project.updatedAt,
      },
      productionQueue: queueItems,
      timeline: timelines,
      promptHistory,
      assets,
    };

    return { success: true, data: backup };
  } catch (err) {
    return { success: false, error: String(err) };
  }
}

/** 下载备份到本地文件 */
export async function downloadBackup(projectId: string, projectName: string): Promise<boolean> {
  const result = await exportBackup(projectId);
  if (!result.success || !result.data) return false;

  const blob = new Blob([JSON.stringify(result.data, null, 2)], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${projectName.replace(/\s+/g, "_")}_backup_${Date.now()}.project.json`;
  a.click();
  URL.revokeObjectURL(url);
  return true;
}

/** 读取备份文件 */
export function readBackupFile(file: File): Promise<{ success: boolean; data?: ProjectBackup; error?: string }> {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const data = JSON.parse(reader.result as string) as ProjectBackup;
        if (data.version !== "2.8") {
          resolve({ success: false, error: `不支持的备份版本: ${data.version}` });
          return;
        }
        resolve({ success: true, data });
      } catch (err) {
        resolve({ success: false, error: "备份文件格式错误" });
      }
    };
    reader.onerror = () => resolve({ success: false, error: "无法读取文件" });
    reader.readAsText(file);
  });
}

/** 管理自动备份：保留最近7份，删除旧的 */
export async function cleanAutoBackups(): Promise<void> {
  try {
    const keys: Array<{ key: string; time: number }> = [];
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith(BACKUP_PREFIX)) {
        const time = parseInt(key.split("-").pop() || "0", 10);
        keys.push({ key, time });
      }
    }
    keys.sort((a, b) => b.time - a.time);
    if (keys.length > MAX_AUTO_BACKUPS) {
      for (const k of keys.slice(MAX_AUTO_BACKUPS)) {
        localStorage.removeItem(k.key);
      }
      logger.info("Backup", `清理旧备份: 删除 ${keys.length - MAX_AUTO_BACKUPS} 份`);
    }
  } catch { /* ignore */ }
}

// ============================================================
// Task Manager — 多任务执行管理器
// ============================================================
// 支持并发控制、任务队列、取消、重试
// ============================================================

import { agnes } from "@/services/agnes";
import { useConfigStore } from "@/stores/configStore";
import { taskPollingService } from "./taskPolling";
import type { UnifiedTask, TaskType, TaskStatus } from "@/stores/taskStore";

export interface ConcurrencyConfig {
  image: number; // 图片任务最大并发
  video: number; // 视频任务最大并发
}

const DEFAULT_CONCURRENCY: ConcurrencyConfig = {
  image: 5,
  video: 3,
};

interface PendingTask {
  task: {
    type: TaskType; model: string; prompt: string;
    id: string; thumbnail: string; taskId: string;
    params?: Record<string, unknown>; duration?: number;
    status: TaskStatus; progress: number;
    resultUrl: string; errorMessage: string;
  };
  resolve: (result: UnifiedTask) => void;
  reject: (error: Error) => void;
}

class TaskManager {
  private concurrency: ConcurrencyConfig = { ...DEFAULT_CONCURRENCY };
  private runningCount = { image: 0, video: 0 };
  private pendingQueue: PendingTask[] = [];
  private abortControllers = new Map<string, AbortController>();

  /**
   * 设置并发数
   */
  setConcurrency(config: Partial<ConcurrencyConfig>): void {
    this.concurrency = { ...this.concurrency, ...config };
  }

  /**
   * 创建并执行一个任务
   */
  async createTask(
    task: { type: TaskType; model: string; prompt: string; id?: string; thumbnail?: string; taskId?: string; params?: Record<string, unknown>; duration?: number }
  ): Promise<UnifiedTask> {
    const { useTaskStore } = await import("@/stores/taskStore");

    const category: "image" | "video" = 
      task.type === "text-to-video" || task.type === "image-to-video" ? "video" : "image";

    // 创建本地任务记录
    const localId = useTaskStore.getState().addTask({
      id: task.id || "",
      taskId: (task as any).taskId || "",
      type: task.type,
      model: task.model,
      prompt: task.prompt,
      status: "queued",
      progress: 0,
      resultUrl: "",
      thumbnail: task.thumbnail || "",
      errorMessage: "",
      params: (task as any).params,
      duration: (task as any).duration,
    });

    // 包装为 Promise
    return new Promise<UnifiedTask>((resolve, reject) => {
      const pending: PendingTask = {
        task: {
          id: localId,
          taskId: task.taskId || "",
          type: task.type,
          model: task.model,
          prompt: task.prompt,
          status: "queued",
          progress: 0,
          resultUrl: "",
          thumbnail: task.thumbnail || "",
          errorMessage: "",
          params: task.params,
          duration: task.duration,
        },
        resolve,
        reject,
      };

      if (this.canRun(category)) {
        this._executeTask(pending, category);
      } else {
        this.pendingQueue.push(pending);
      }
    });
  }

  /**
   * 取消任务
   */
  cancelTask(localId: string): void {
    // 检查是否在队列中
    const queueIndex = this.pendingQueue.findIndex(
      (p) => p.task.id === localId
    );
    if (queueIndex >= 0) {
      const [removed] = this.pendingQueue.splice(queueIndex, 1);
      removed.reject(new Error("已取消"));
      return;
    }

    // 检查是否正在运行
    const controller = this.abortControllers.get(localId);
    if (controller) {
      controller.abort();
    }

    // 停止轮询
    taskPollingService.stopPolling(localId);
  }

  /**
   * 重试任务
   */
  async retryTask(localId: string): Promise<UnifiedTask | null> {
    const { useTaskStore } = await import("@/stores/taskStore");
    const task = useTaskStore.getState().getTaskById(localId);
    if (!task) return null;

    // 更新状态为重试
    useTaskStore.getState().updateTask(localId, {
      status: "queued",
      progress: 0,
      errorMessage: "",
    });

    // 根据类型重新执行
    return this.createTask({
      id: localId,
      type: task.type,
      model: task.model,
      prompt: task.prompt,
      params: task.params,
      duration: task.duration,
      thumbnail: task.thumbnail,
    });
  }

  /**
   * 重新执行（使用新参数）
   */
  async recreateTask(
    oldId: string,
    newParams: Partial<Omit<UnifiedTask, "id" | "createTime" | "updateTime">>
  ): Promise<UnifiedTask> {
    const { useTaskStore } = await import("@/stores/taskStore");
    const oldTask = useTaskStore.getState().getTaskById(oldId);
    if (!oldTask) throw new Error("原任务不存在");

    return this.createTask({
      type: newParams.type || oldTask.type,
      model: newParams.model || oldTask.model,
      prompt: newParams.prompt || oldTask.prompt,
      params: newParams.params || oldTask.params,
      duration: newParams.duration || oldTask.duration,
      thumbnail: newParams.thumbnail || oldTask.thumbnail,
    });
  }

  // ---------------------------------------------------------
  // 内部方法
  // ---------------------------------------------------------

  private canRun(category: "image" | "video"): boolean {
    const max = this.concurrency[category];
    return this.runningCount[category] < max;
  }

  private async _executeTask(pending: PendingTask, category: "image" | "video"): Promise<void> {
    this.runningCount[category]++;
    const { useTaskStore } = await import("@/stores/taskStore");
    const localId = pending.task.id;

    try {
      useTaskStore.getState().updateTask(localId, { status: "processing" });

      const config = useConfigStore.getState();
      const controller = new AbortController();
      this.abortControllers.set(localId, controller);

      // 根据类型执行
      if (category === "image") {
        await this._executeImageTask(localId, pending.task, controller.signal);
      } else {
        await this._executeVideoTask(localId, pending.task);
      }

      // 成功
      const updated = useTaskStore.getState().getTaskById(localId);
      if (updated) pending.resolve(updated);
    } catch (err: unknown) {
      const isCancelled = err instanceof Error && 
        (err.name === "AbortError" || err.message.includes("取消"));

      useTaskStore.getState().updateTask(localId, {
        status: isCancelled ? "cancelled" : "failed",
        errorMessage: err instanceof Error ? err.message : "生成失败",
      });

      pending.reject(err instanceof Error ? err : new Error("生成失败"));
    } finally {
      this.runningCount[category]--;
      this.abortControllers.delete(localId);

      // 执行下一个等待的任务
      this._processQueue(category);
    }
  }

  private async _executeImageTask(
    localId: string,
    task: { type: TaskType; model: string; prompt: string; id: string; thumbnail: string; taskId: string; params?: Record<string, unknown>; duration?: number; status: TaskStatus; progress: number; resultUrl: string; errorMessage: string },
    signal: AbortSignal
  ): Promise<void> {
    const { useTaskStore } = await import("@/stores/taskStore");

    let result: { url: string; revisedPrompt?: string }[];

      if (task.type === "text-to-image") {
        result = await agnes.image.generate({
          prompt: task.prompt,
          size: ((task.params?.size || "1024x1024") as "1024x1024" | "512x512" | "256x256" | "768x1344" | "1344x768" | "1024x1792" | "1792x1024"),
          n: (task.params?.n as number) || 1,
          model: task.model,
        });
      } else {
        // image-to-image - 需要从 thumbnail 还原
        throw new Error("图生图需要上传文件，请使用页面上的生成功能");
      }

      if (result && result.length > 0) {
        useTaskStore.getState().updateTask(localId, {
          status: "completed",
          progress: 100,
          resultUrl: result[0].url,
        });
      }
  }

  private async _executeVideoTask(
    localId: string,
    task: { type: TaskType; model: string; prompt: string; id: string; thumbnail: string; taskId: string; params?: Record<string, unknown>; duration?: number; status: TaskStatus; progress: number; resultUrl: string; errorMessage: string }
  ): Promise<void> {
    const { useTaskStore } = await import("@/stores/taskStore");

    let taskResult: { taskId: string; videoId: string };

      if (task.type === "text-to-video") {
        const duration = (task.params?.duration as number) || 5;
        const fps = (task.params?.fps as number) || 24;
        const numFrames = duration * fps;
        const aspectRatio = (task.params?.aspect_ratio as string) || "16:9";
        const [w, h] = aspectRatio === "16:9" ? [1152, 768] : aspectRatio === "9:16" ? [768, 1152] : [1024, 1024];

        taskResult = await agnes.video.create({
          prompt: task.prompt,
          model: task.model,
          height: h,
          width: w,
          numFrames,
          frameRate: fps,
        }) as unknown as { taskId: string; videoId: string };
      } else {
        throw new Error("图生视频需要上传文件，请使用页面上的生成功能");
      }

      const videoId = taskResult.videoId || taskResult.taskId;
      // 开始轮询
      taskPollingService.startPolling(localId, videoId, task.type as "text-to-video" | "image-to-video");
  }

  private _processQueue(category: "image" | "video"): void {
    if (!this.canRun(category)) return;

    const idx = this.pendingQueue.findIndex((p) => {
      const t = p.task.type;
      const cat = t === "text-to-video" || t === "image-to-video" ? "video" : "image";
      return cat === category;
    });

    if (idx >= 0) {
      const [pending] = this.pendingQueue.splice(idx, 1);
      this._executeTask(pending, category);
    }
  }
}

// 全局单例
export const taskManager = new TaskManager();

// ============================================================
// Task Polling Service — 后台轮询管理器
// ============================================================
// 统一管理所有任务的轮询，避免每个页面自己轮询
// ============================================================

import { agnes } from "@/services/agnes";
import { useTaskStore, type UnifiedTask } from "@/stores/taskStore";

interface PollEntry {
  taskId: string;
  localId: string;
  type: "text-to-video" | "image-to-video";
  controller: AbortController;
  lastProgress: number;
  isRunning: boolean;
}

class TaskPollingService {
  private pollMap = new Map<string, PollEntry>();
  private callbacks = new Map<string, (progress: number) => void>();

  /**
   * 开始轮询一个视频任务
   */
  startPolling(
    localId: string,
    apiTaskId: string,
    taskType: "text-to-video" | "image-to-video",
    onProgress?: (progress: number) => void
  ): void {
    // 如果已经在轮询，不做重复启动
    if (this.pollMap.has(localId) && this.pollMap.get(localId)!.isRunning) {
      return;
    }

    const controller = new AbortController();
    const entry: PollEntry = {
      taskId: apiTaskId,
      localId,
      type: taskType,
      controller,
      lastProgress: -1,
      isRunning: true,
    };
    this.pollMap.set(localId, entry);
    if (onProgress) this.callbacks.set(localId, onProgress);

    // 开始轮询
    this._poll(entry).finally(() => {
      entry.isRunning = false;
    });
  }

  /**
   * 停止轮询
   */
  stopPolling(localId: string): void {
    const entry = this.pollMap.get(localId);
    if (entry) {
      entry.controller.abort();
      this.pollMap.delete(localId);
      this.callbacks.delete(localId);
    }
  }

  /**
   * 停止所有轮询
   */
  stopAll(): void {
    for (const [id, entry] of this.pollMap) {
      entry.controller.abort();
    }
    this.pollMap.clear();
    this.callbacks.clear();
  }

  /**
   * 是否正在轮询
   */
  isPolling(localId: string): boolean {
    return this.pollMap.has(localId) && this.pollMap.get(localId)!.isRunning;
  }

  /**
   * 获取当前轮询数
   */
  getActivePollCount(): number {
    let count = 0;
    for (const entry of this.pollMap.values()) {
      if (entry.isRunning) count++;
    }
    return count;
  }

  // ---------------------------------------------------------
  // 内部轮询逻辑
  // ---------------------------------------------------------
  private async _poll(entry: PollEntry): Promise<void> {
    const store = useTaskStore.getState();
    try {
      const result = await agnes.video.poll(entry.taskId, {
        interval: 3000,
        maxInterval: 15000,
        timeout: 600000,
        signal: entry.controller.signal,
        onProgress: (p) => {
          const cb = this.callbacks.get(entry.localId);
          if (cb) cb(p.progress);
          // 更新 store
          useTaskStore.getState().updateTask(entry.localId, {
            progress: p.progress,
            status: p.status === "completed" ? "completed" : "processing",
          });
        },
      });

      // 完成
      useTaskStore.getState().updateTask(entry.localId, {
        status: "completed",
        progress: 100,
        resultUrl: result.url,
        duration: result.duration,
        updateTime: Date.now(),
      });
    } catch (err: unknown) {
      const isCancelled = err instanceof Error && err.message.includes("取消");
      useTaskStore.getState().updateTask(entry.localId, {
        status: isCancelled ? "cancelled" : "failed",
        errorMessage: err instanceof Error ? err.message : "生成失败",
        updateTime: Date.now(),
      });
    } finally {
      this.pollMap.delete(entry.localId);
      this.callbacks.delete(entry.localId);
    }
  }
}

// 全局单例
export const taskPollingService = new TaskPollingService();

import { create } from "zustand";
import { persist } from "zustand/middleware";
import type { AgnesConfig, ConfigSource } from "@/services/agnes";

export interface ConfigState extends AgnesConfig {
  setApiKey: (key: string) => void;
  setBaseUrl: (url: string) => void;
  setModel: (model: string) => void;
  setTextToImageModel: (model: string) => void;
  setImageToImageModel: (model: string) => void;
  setTextToVideoModel: (model: string) => void;
  setImageToVideoModel: (model: string) => void;
  reset: () => void;
  isConfigured: boolean;
  /** 当前配置来源 */
  configSource: ConfigSource;
}

const CORRECT_BASE_URL = "https://apihub.agnes-ai.com/v1";

const DEFAULTS: AgnesConfig & { isConfigured: boolean; configSource: ConfigSource } = {
  apiKey: "",
  baseUrl: CORRECT_BASE_URL,
  model: "agnes-image-2.1-flash",
  textToImageModel: "agnes-image-2.1-flash",
  imageToImageModel: "agnes-image-2.1-flash",
  textToVideoModel: "agnes-video-v2.0",
  imageToVideoModel: "agnes-video-v2.0",
  isConfigured: false,
  configSource: "default",
};

// 自动修正常见错误的 Base URL
function normalizeBaseUrl(url: string): string {
  const trimmed = url.trim().replace(/\/+$/, "");
  if (trimmed.includes("api.agnesai.com")) {
    console.warn("[ConfigStore] 检测到错误的域名 api.agnesai.com，自动修正为 apihub.agnes-ai.com");
    return trimmed.replace("api.agnesai.com", "apihub.agnes-ai.com");
  }
  return trimmed;
}

// 检测环境变量配置
function detectEnvConfig(): { apiKey: string; source: ConfigSource } {
  // 服务端环境变量
  if (typeof process !== "undefined") {
    const serverKey = process.env?.AGNES_API_KEY;
    if (serverKey) return { apiKey: serverKey, source: "env" };

    const publicKey = process.env?.NEXT_PUBLIC_AGNES_API_KEY;
    if (publicKey) return { apiKey: publicKey, source: "nextPublicEnv" };
  }
  return { apiKey: "", source: "default" };
}

export const useConfigStore = create<ConfigState>()(
  persist(
    (set, get) => {
      // 初始检测环境变量
      const { apiKey: envKey, source: envSource } = detectEnvConfig();
      const isConfiguredFromEnv = !!envKey;

      return {
        ...DEFAULTS,
        apiKey: envKey || DEFAULTS.apiKey,
        configSource: envSource,
        isConfigured: isConfiguredFromEnv || false,

        setApiKey: (apiKey) => set({
          apiKey,
          configSource: "localStorage",
          isConfigured: !!apiKey && !!get().baseUrl,
        }),

        setBaseUrl: (baseUrl) => set({
          baseUrl: normalizeBaseUrl(baseUrl),
          isConfigured: !!get().apiKey && !!baseUrl,
        }),

        setModel: (model) => set({ model }),
        setTextToImageModel: (textToImageModel) => set({ textToImageModel }),
        setImageToImageModel: (imageToImageModel) => set({ imageToImageModel }),
        setTextToVideoModel: (textToVideoModel) => set({ textToVideoModel }),
        setImageToVideoModel: (imageToVideoModel) => set({ imageToVideoModel }),

        reset: () => set({ ...DEFAULTS, ...detectEnvConfig() }),
      };
    },
    {
      name: "agnes-api-config",
      migrate: (persisted: unknown, version: number) => {
        const state = persisted as Record<string, unknown>;
        if (state?.baseUrl && typeof state.baseUrl === "string") {
          state.baseUrl = normalizeBaseUrl(state.baseUrl as string);
        }
        // 合并环境变量
        const { apiKey: envKey, source: envSource } = detectEnvConfig();
        return {
          ...DEFAULTS,
          ...state,
          apiKey: envKey || ((state as any)?.apiKey ?? DEFAULTS.apiKey),
          configSource: envSource || "localStorage",
          isConfigured: !!(envKey || (state as any)?.apiKey),
        } as ConfigState;
      },
      version: 2,
    }
  )
);

import { create } from "zustand";
import { persist } from "zustand/middleware";
import type { Project, Scene, ProjectStatus } from "@/types";

interface ProjectStoreState {
  projects: Project[];
  addProject: (proj: Partial<Project> & { name: string }) => string;
  updateProject: (id: string, patch: Partial<Project>) => void;
  removeProject: (id: string) => void;
  getProjectById: (id: string) => Project | undefined;
  searchProjects: (query: string) => Project[];
  addSceneToProject: (projectId: string, scene: Scene) => void;
  removeSceneFromProject: (projectId: string, sceneId: string) => void;
  reorderScenes: (projectId: string, sceneIds: string[]) => void;
  /** V2.4: Lock a character to project */
  lockCharacter: (projectId: string, characterId: string) => void;
  /** V2.4: Unlock a character */
  unlockCharacter: (projectId: string, characterId: string) => void;
  /** V2.4: Set style DNA */
  setStyleDna: (projectId: string, dna: string) => void;
}

let _prjCounter = 0;
function genProjectId(): string {
  _prjCounter++; return `proj-${Date.now()}-${_prjCounter}-${Math.random().toString(36).slice(2, 8)}`;
}

export const useProjectStore = create<ProjectStoreState>()(
  persist(
    (set, get) => ({
      projects: [],
      addProject: (data) => {
        const id = data.id || genProjectId();
        const now = Date.now();
        set((s) => ({
          projects: [{
            ...data, id, scenes: [], characters: [], assets: [],
            styleDna: data.styleDna || "",
            storyScript: data.storyScript || "",
            lockedCharacterIds: data.lockedCharacterIds || [],
            createdAt: now, updatedAt: now,
          } as Project, ...s.projects],
        }));
        return id;
      },
      updateProject: (id, patch) => set((s) => ({
        projects: s.projects.map((p) => p.id === id ? { ...p, ...patch, updatedAt: Date.now() } : p),
      })),
      removeProject: (id) => set((s) => ({ projects: s.projects.filter((p) => p.id !== id) })),
      getProjectById: (id) => get().projects.find((p) => p.id === id),
      searchProjects: (query) => {
        let results = get().projects;
        if (query) { const q = query.toLowerCase(); results = results.filter((p) => p.name.toLowerCase().includes(q) || p.description.toLowerCase().includes(q) || p.tags.some((t) => t.toLowerCase().includes(q))); }
        return results.sort((a, b) => b.updatedAt - a.updatedAt);
      },
      addSceneToProject: (projectId, scene) => set((s) => ({
        projects: s.projects.map((p) => p.id === projectId ? { ...p, scenes: [...p.scenes, scene], updatedAt: Date.now() } : p),
      })),
      removeSceneFromProject: (projectId, sceneId) => set((s) => ({
        projects: s.projects.map((p) => p.id === projectId ? { ...p, scenes: p.scenes.filter((s) => s.id !== sceneId), updatedAt: Date.now() } : p),
      })),
      reorderScenes: (projectId, sceneIds) => set((s) => ({
        projects: s.projects.map((p) => p.id === projectId ? {
          ...p, scenes: sceneIds.map((id) => p.scenes.find((s) => s.id === id)).filter(Boolean) as Scene[],
          updatedAt: Date.now(),
        } : p),
      })),
      lockCharacter: (projectId, characterId) => set((s) => ({
        projects: s.projects.map((p) => p.id === projectId ? {
          ...p, lockedCharacterIds: [...new Set([...p.lockedCharacterIds, characterId])],
          updatedAt: Date.now(),
        } : p),
      })),
      unlockCharacter: (projectId, characterId) => set((s) => ({
        projects: s.projects.map((p) => p.id === projectId ? {
          ...p, lockedCharacterIds: p.lockedCharacterIds.filter((c) => c !== characterId),
          updatedAt: Date.now(),
        } : p),
      })),
      setStyleDna: (projectId, dna) => set((s) => ({
        projects: s.projects.map((p) => p.id === projectId ? { ...p, styleDna: dna, updatedAt: Date.now() } : p),
      })),
    }),
    { name: "agnes-project-store", version: 2 }
  )
);

﻿// ========== PromptHistoryStore — V2.8 ==========
// 持久化保存 Prompt 历史版本，每镜头最多 50 版本
import { create } from "zustand";
import { persist, createJSONStorage } from "zustand/middleware";
import { indexedDBStorage } from "@/services/IndexedDBStorage";
import { logger } from "@/lib/logger";

export interface PromptVersion {
  prompt: string;
  savedAt: number;
}

interface PromptHistoryState {
  /** key: shotId, value: versions array */
  history: Record<string, PromptVersion[]>;

  /** 保存一个版本 */
  saveVersion: (shotId: string, prompt: string) => void;

  /** 获取某个镜头的所有版本 */
  getVersions: (shotId: string) => PromptVersion[];

  /** 恢复某个版本（返回该版本的 prompt） */
  getVersion: (shotId: string, index: number) => string | null;

  /** 删除某个版本 */
  deleteVersion: (shotId: string, index: number) => void;

  /** 删除某个镜头的所有版本 */
  clearShotHistory: (shotId: string) => void;

  /** 获取历史统计 */
  getStats: () => { totalShots: number; totalVersions: number; };
}

const MAX_VERSIONS_PER_SHOT = 50;

export const usePromptHistoryStore = create<PromptHistoryState>()(
  persist(
    (set, get) => ({
      history: {},

      saveVersion: (shotId, prompt) => set((s) => {
        const history = s.history || {};
        const existing = history[shotId] || [];
        // 避免重复保存相同 prompt
        if (existing.length > 0 && existing[0].prompt === prompt) return s;
        const versions = [{ prompt, savedAt: Date.now() }, ...existing];
        // 超出限制，删除最旧版本
        if (versions.length > MAX_VERSIONS_PER_SHOT) {
          versions.pop();
        }
        logger.info("PromptHistory", `保存版本: shot=${shotId.slice(-8)}, 版本数=${versions.length}`);
        return { history: { ...history, [shotId]: versions } };
      }),

      getVersions: (shotId) => (get().history || {})[shotId] || [],

      getVersion: (shotId, index) => {
        const versions = (get().history || {})[shotId];
        if (!versions || index < 0 || index >= versions.length) return null;
        return versions[index].prompt;
      },

      deleteVersion: (shotId, index) => set((s) => {
        const history = s.history || {};
        const versions = (history[shotId] || []).filter((_, i) => i !== index);
        return { history: { ...history, [shotId]: versions } };
      }),

      clearShotHistory: (shotId) => set((s) => {
        const { [shotId]: _removed, ...rest } = s.history || {};
        return { history: rest };
      }),

      getStats: () => {
        const h = get().history || {};
        const totalShots = Object.keys(h).length;
        const totalVersions = Object.values(h).reduce((sum, v) => sum + v.length, 0);
        return { totalShots, totalVersions };
      },
    }),
    {
      name: "agnes-prompt-history",
      version: 1,
      storage: createJSONStorage(() => indexedDBStorage),
    }
  )
);

import { create } from "zustand";
import { persist } from "zustand/middleware";
import type { PromptTemplate, PromptCategory, PromptVariable } from "@/types";

interface PromptStoreState {
  prompts: PromptTemplate[];
  addPrompt: (prompt: Omit<PromptTemplate, "id" | "createdAt" | "updatedAt" | "usageCount">) => string;
  updatePrompt: (id: string, patch: Partial<PromptTemplate>) => void;
  removePrompt: (id: string) => void;
  toggleFavorite: (id: string) => void;
  incrementUsage: (id: string) => void;
  clonePrompt: (id: string) => string | null;
  getPromptById: (id: string) => PromptTemplate | undefined;
  searchPrompts: (query: string, category?: PromptCategory) => PromptTemplate[];
}

let _pCounter = 0;
function genPromptId(): string {
  _pCounter++; return `prompt-${Date.now()}-${_pCounter}-${Math.random().toString(36).slice(2, 8)}`;
}

export const usePromptStore = create<PromptStoreState>()(
  persist(
    (set, get) => ({
      prompts: [],
      addPrompt: (data) => {
        const id = genPromptId();
        const now = Date.now();
        const prompt: PromptTemplate = { ...data, id, usageCount: 0, createdAt: now, updatedAt: now };
        set((s) => ({ prompts: [prompt, ...s.prompts] }));
        return id;
      },
      updatePrompt: (id, patch) => set((s) => ({ prompts: s.prompts.map((p) => p.id === id ? { ...p, ...patch, updatedAt: Date.now() } : p) })),
      removePrompt: (id) => set((s) => ({ prompts: s.prompts.filter((p) => p.id !== id) })),
      toggleFavorite: (id) => set((s) => ({ prompts: s.prompts.map((p) => p.id === id ? { ...p, isFavorite: !p.isFavorite, updatedAt: Date.now() } : p) })),
      incrementUsage: (id) => set((s) => ({ prompts: s.prompts.map((p) => p.id === id ? { ...p, usageCount: p.usageCount + 1 } : p) })),
      clonePrompt: (id) => {
        const orig = get().prompts.find((p) => p.id === id);
        if (!orig) return null;
        const newId = genPromptId();
        const now = Date.now();
        const cloned: PromptTemplate = { ...orig, id: newId, name: `${orig.name} (Copy)`, usageCount: 0, isFavorite: false, createdAt: now, updatedAt: now };
        set((s) => ({ prompts: [cloned, ...s.prompts] }));
        return newId;
      },
      getPromptById: (id) => get().prompts.find((p) => p.id === id),
      searchPrompts: (query, category) => {
        let results = get().prompts;
        if (query) { const q = query.toLowerCase(); results = results.filter((p) => p.name.toLowerCase().includes(q) || p.content.toLowerCase().includes(q) || p.tags.some((t) => t.toLowerCase().includes(q))); }
        if (category && category !== "general") results = results.filter((p) => p.category === category);
        return results.sort((a, b) => (b.isFavorite ? 1 : 0) - (a.isFavorite ? 1 : 0) || b.updatedAt - a.updatedAt);
      },
    }),
    { name: "agnes-prompt-store", version: 1 }
  )
);

export function extractVariables(content: string): string[] {
  const matches = content.match(/\{(\w+)\}/g);
  return matches ? [...new Set(matches.map((m) => m.slice(1, -1)))] : [];
}

export function renderPrompt(content: string, variables: Record<string, string>): string {
  return content.replace(/\{(\w+)\}/g, (_, key) => variables[key] || `{${key}}`);
}

import { create } from "zustand";
import { persist } from "zustand/middleware";
import type { Scene, Shot, ShotType, TransitionType } from "@/types";

interface StoryboardStoreState {
  scenes: Scene[];
  addScene: (scene: Omit<Scene, "id" | "shots" | "createdAt" | "updatedAt">) => string;
  updateScene: (id: string, patch: Partial<Scene>) => void;
  removeScene: (id: string) => void;
  reorderScenes: (sceneIds: string[]) => void;
  addShot: (sceneId: string, shot: Omit<Shot, "id" | "createdAt" | "updatedAt">) => string;
  updateShot: (sceneId: string, shotId: string, patch: Partial<Shot>) => void;
  removeShot: (sceneId: string, shotId: string) => void;
  reorderShots: (sceneId: string, shotIds: string[]) => void;
  getSceneById: (id: string) => Scene | undefined;
  getScenesByProjectId: (projectId: string) => Scene[];
}

let _sCounter = 0;
function genSceneId(): string {
  _sCounter++; return `scene-${Date.now()}-${_sCounter}-${Math.random().toString(36).slice(2, 8)}`;
}
function genShotId(): string {
  _sCounter++; return `shot-${Date.now()}-${_sCounter}-${Math.random().toString(36).slice(2, 8)}`;
}

export const useStoryboardStore = create<StoryboardStoreState>()(
  persist(
    (set, get) => ({
      scenes: [],
      addScene: (data) => {
        const id = genSceneId(); const now = Date.now();
        set((s) => ({ scenes: [...s.scenes, { ...data, id, shots: [], createdAt: now, updatedAt: now }] }));
        return id;
      },
      updateScene: (id, patch) => set((s) => ({ scenes: s.scenes.map((sc) => sc.id === id ? { ...sc, ...patch, updatedAt: Date.now() } : sc) })),
      removeScene: (id) => set((s) => ({ scenes: s.scenes.filter((sc) => sc.id !== id) })),
      reorderScenes: (sceneIds) => set((s) => ({ scenes: sceneIds.map((id) => s.scenes.find((sc) => sc.id === id)).filter(Boolean) as Scene[] })),
      addShot: (sceneId, data) => {
        const id = genShotId(); const now = Date.now();
        const shot: Shot = { ...data, id, createdAt: now, updatedAt: now };
        set((s) => ({ scenes: s.scenes.map((sc) => sc.id === sceneId ? { ...sc, shots: [...sc.shots, shot], updatedAt: now } : sc) }));
        return id;
      },
      updateShot: (sceneId, shotId, patch) => set((s) => ({ scenes: s.scenes.map((sc) => sc.id === sceneId ? { ...sc, shots: sc.shots.map((sh) => sh.id === shotId ? { ...sh, ...patch, updatedAt: Date.now() } : sh), updatedAt: Date.now() } : sc) })),
      removeShot: (sceneId, shotId) => set((s) => ({ scenes: s.scenes.map((sc) => sc.id === sceneId ? { ...sc, shots: sc.shots.filter((sh) => sh.id !== shotId), updatedAt: Date.now() } : sc) })),
      reorderShots: (sceneId, shotIds) => set((s) => ({ scenes: s.scenes.map((sc) => sc.id === sceneId ? { ...sc, shots: shotIds.map((id) => sc.shots.find((sh) => sh.id === id)).filter(Boolean) as Shot[] } : sc) })),
      getSceneById: (id) => get().scenes.find((sc) => sc.id === id),
      getScenesByProjectId: (projectId) => get().scenes.filter((sc) => sc.projectId === projectId).sort((a, b) => a.order - b.order),
    }),
    { name: "agnes-storyboard-store", version: 1 }
  )
);
